#include<bits/stdc++.h>
using namespace std;
int ans=0,n;
long long flip(long long x) {
	long long y = 0;
	while (x) {
		y += x % 10;
		x /= 10;
		y *= 10;
	}
	y /= 10;
	return y;
}
bool prime_number(long long x) { 
	for (int i = 2; i * i <= x; i++) if (x % i == 0) return false;
	return true;
}
int main() {
	cin>>n;
	for(int i=11;i<=n;i++) if(i==flip(i)) if(prime_number(i)) ans++;
	cout<<ans;
	return 0;
}
